int align = ((data_ptr + 1) & 0xfffe) - (data_ptr & 0xffff);  // == data_ptr & 1 (0 or 1)
if (rcx_3 < align) error;                                     // caller pre-checks size>=align
result = DfsReferralParseStringEntry(&var_58, &var_88, &DestinationString, align, rcx_3, data_ptr);
// ... allocation path (unchanged in behavior):
int32_t r13_2 = DestinationString + DestinationString_1 + 0xbc;  // size from validated lengths
void* P = ExAllocatePoolWithTag(NonPagedPoolNx, r13_2, 0x46736644);
memmove(&P[0xB0], DestinationString.Buffer, DestinationString.Length);  // copies exactly Length

